42	const TRACKGENTIC_DIR = ".trackgentic";
43	
44	/**
45	 * Default config.json contents.
46	 */
47	const DEFAULT_CONFIG: ConfigFile = {
48	  auth: {
49	    mode: "open",
50	    defaultUser: "anonymous",
51	  },
52	};
53	
54	/**
55	 * Default index.json contents.
56	 */
