58	  open: [],
59	  closed: [],
60	  childrenOf: {},
61	};
62	
63	/**
64	 * Default dependencies.json contents.
65	 */
66	const DEFAULT_DEPENDENCIES: DependenciesFile = {
67	  blockedBy: {},
68	  blocks: {},
69	};
70	
