448	  // ─── Comments ─────────────────────────────────────────────────────
449	
450	  /**
451	   * Add a comment to an issue.
452	   */
453	  async commentsAdd(id: IssueId, params: CommentAddParams): Promise<CommentAddResult> {
454	    const trackerDir = resolveTrackerDir(this.cwd);
455	    if (!trackerDir) {
456	      throw new TrackgenticError(
457	        ErrorCodes.NOT_INITIALIZED.result,
458	        "No .trackgentic/ directory found. Run `trackgentic init` first.",
459	        ErrorCodes.NOT_INITIALIZED.exitCode,
460	      );
461	    }
462	
463	    const config = await readJSON<ConfigFile>(join(trackerDir, "config.json"));
464	    const users = await readJSON<UsersFile>(join(trackerDir, "users.json"));
465	    const authResult = resolveAuthor({ config, users, requiresWrite: true });
466	    if (authResult instanceof TrackgenticError) return authResult;
467	    const author = params.author ?? authResult.author;
468	
469	    const index = await readIndex(trackerDir);
470	    const entry = findEntry(index, id);
471	    if (!entry) {
472	      throw new TrackgenticError(
473	        ErrorCodes.NOT_FOUND.result,
474	        `Issue ${id} not found in index.`,
475	        ErrorCodes.NOT_FOUND.exitCode,
476	      );
477	    }
478	
