680	  /**
681	   * Register a new user. Does NOT require auth (bootstrap mechanism).
682	   */
683	  async usersRegister(name: string): Promise<UsersRegisterResult> {
684	    const trackerDir = resolveTrackerDir(this.cwd);
685	    if (!trackerDir) {
686	      throw new TrackgenticError(
687	        ErrorCodes.NOT_INITIALIZED.result,
688	        "No .trackgentic/ directory found. Run `trackgentic init` first.",
689	        ErrorCodes.NOT_INITIALIZED.exitCode,
690	      );
691	    }
692	
693	    const lowerName = name.toLowerCase();
694	
695	    // Reject reserved name
696	    if (lowerName === "anonymous") {
697	      return {
698	        result: "USER_ALREADY_EXISTS",
699	        message: `"anonymous" is a reserved name and cannot be registered.`,
700	      };
701	    }
702	
703	    const users = await readJSON<UsersFile>(join(trackerDir, "users.json"));
704	
705	    // Check uniqueness
706	    if (users.users.find((u) => u.name === lowerName)) {
707	      return {
708	        result: "USER_ALREADY_EXISTS",
709	        message: `User "${lowerName}" already exists.`,
710	      };
711	    }
712	
713	    const token = generateToken();
714	    const newUser: UserEntry = {
715	      name: lowerName,
716	      token,
717	      registeredAt: new Date().toISOString(),
718	    };
719	
720	    users.users.push(newUser);
721	    await atomicWriteJSON(join(trackerDir, "users.json"), users);
722	
723	    return { result: "OK", name: lowerName, token };
724	  }
