804	    const authResult = resolveAuthor({ config, users, requiresWrite: true });
805	    if (authResult instanceof TrackgenticError) {
806	      throw authResult;
807	    }
808	
809	    const callerName = authResult.author;
810	    const lowerName = name.toLowerCase();
811	
812	    // Self-service check: caller must be the target user
813	    if (callerName !== lowerName) {
814	      return {
815	        result: "INVALID_TOKEN",
816	        message: `You can only regenerate your own token.`,
817	      };
818	    }
819	
820	    const user = users.users.find((u) => u.name === lowerName);
