822	      return {
823	        result: "USER_NOT_FOUND",
824	        message: `User "${lowerName}" not found.`,
825	      };
826	    }
827	
828	    const newToken = generateToken();
829	    user.token = newToken;
830	    await atomicWriteJSON(join(trackerDir, "users.json"), users);
831	
832	    return { result: "OK", name: lowerName, token: newToken };
