const promotions: Array<{ issueId: IssueId; event: Event }> = [];

let currentParentEntry: IndexEntry | null = parentEntry;
const currentChildStatus: IssueStatus = childStatus;

while (currentParentEntry) {
  // If child's status is not after parent's status, no promotion needed
  if (!isStatusAfter(currentChildStatus, currentParentEntry.status)) {
    break;
  }

  const now = new Date().toISOString();
  const event: Event = {
    type: "update",
    timestamp: now,
    author: "system",
    content: {
      status: currentChildStatus,
      reason: `auto-promoted: child advanced to '${currentChildStatus}'`,
    },
  };

  promotions.push({ issueId: currentParentEntry.id, event });

