1	import type { Event, IndexEntry, IndexFile, IssueId, IssueStatus } from "../types";
2	
3	/**
4	 * Status progression order — used to compare status positions.
5	 */
6	const STATUS_ORDER: IssueStatus[] = ["idea", "todo", "in-progress", "done", "closed"];
7	
8	/**
9	 * Check if childStatus is strictly after parentStatus in the progression.
10	 * Progression: idea -> todo -> in-progress -> done -> closed
11	 */
12	export function isStatusAfter(childStatus: IssueStatus, parentStatus: IssueStatus): boolean {
13	  return STATUS_ORDER.indexOf(childStatus) > STATUS_ORDER.indexOf(parentStatus);
14	}
15	
16	/**
17	 * Validate that a parent can accept a new child.
18	 * Returns an error message if the parent is closed, null otherwise.
19	 */
20	export function validateNewChild(parentEntry: IndexEntry | null): string | null {
21	  if (!parentEntry) return null; // No parent — no constraint
22	  if (parentEntry.status === "closed") {
23	    return "Cannot add child to closed parent";
24	  }
25	  return null;
26	}
27	
28	/**
29	 * Validate that a parent can transition to the target status.
30	 * Returns an error message if downward constraints are violated, null otherwise.
31	 * Rule: parent cannot move to done/closed if any child has status before done/closed.
32	 */
33	export function validateParentStatusChange(
34	  index: IndexFile,
35	  childEntries: IndexEntry[],
36	  targetStatus: IssueStatus,
37	): string | null {
38	  // Only done/closed have downward constraints
39	  if (targetStatus !== "done" && targetStatus !== "closed") return null;
40	
41	  for (const child of childEntries) {
42	    if (!isStatusAfter(child.status, "done") && child.status !== "done") {
43	      return `Cannot set parent to ${targetStatus}: child ${child.id} has status '${child.status}'`;
44	    }
45	  }
46	
47	  return null;
48	}
49	
50	/**
51	 * Determine which children need to be auto-closed when parent closes.
52	 * Returns entries that are done (they can be auto-closed).
53	 * Does NOT return non-done children (those BLOCK the closure — caller handles that).
54	 */
55	export function getClosableChildren(childEntries: IndexEntry[]): IndexEntry[] {
56	  return childEntries.filter((entry) => entry.status === "done");
57	}
58	
59	/**
60	 * Auto-promote parent if child's new status is past parent's status.
61	 * Returns update events to apply to parents (walks up recursively).
62	 * Each event has author: "system" and a reason field explaining the promotion.
63	 *
64	 * @param index - current index
65	 * @param parentEntry - the direct parent's index entry
66	 * @param childStatus - the child's new status
67	 * @param findEntry - lookup function to find entries by id across both arrays
68	 * @returns array of { issueId, event } for system-authored promotions
69	 */
70	export function computeUpwardPromotions(
71	  index: IndexFile,
72	  parentEntry: IndexEntry,
73	  childStatus: IssueStatus,
74	  findEntry: (id: IssueId) => IndexEntry | null,
75	): Array<{ issueId: IssueId; event: Event }> {
76	  const promotions: Array<{ issueId: IssueId; event: Event }> = [];
77	
78	  let currentParentEntry: IndexEntry | null = parentEntry;
79	
80	  while (currentParentEntry) {
81	    // If child's status is not after parent's status, no promotion needed
82	    if (!isStatusAfter(childStatus, currentParentEntry.status)) {
83	      break;
84	    }
85	
86	    const now = new Date().toISOString();
87	    const event: Event = {
88	      type: "update",
89	      timestamp: now,
90	      author: "system",
91	      content: {
92	        status: childStatus,
93	        reason: `auto-promoted: child advanced to '${childStatus}'`,
94	      },
95	    };
96	
97	    promotions.push({ issueId: currentParentEntry.id, event });
98	
99	    // Check if this parent itself has a parent
100	    if (!currentParentEntry.parentId) break;
101	    const grandParentEntry = findEntry(currentParentEntry.parentId);
102	    currentParentEntry = grandParentEntry;
103	  }
104	
105	  return promotions;
106	}
